LAYER
	NAME "lotes_wgs84"
	GROUP "COFOPRI"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/allpa/cofopri/lotes.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, cod_lote, cod_mzna, cod_sect, id_lote, hab_urbana, mzna_muni, lote_muni, nro_unidad, niveles, zonificaci, estructura, area_ter, area_con, id_dist, id_prov, id_dpto, area_grafi, cuc, geom FROM cofopri.lotes_wgs84) as sbn using unique gid using srid=4326"
    FILTER ("[id_dpto]" IN "08")
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
		"init=epsg:4326"
	END
	CLASSITEM "gid"
	LABELMAXSCALEDENOM 2000000
	LABELMAXSCALE 2000000
	METADATA
		"wms_group_title" "COFOPRI"
		"queryable" "true"
		"wms_metadataurl_href" "LUISAMOS"
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Formalización - Lotes (WGS84)"
		"wms_abstract" "Formalización - Lotes (WGS84) || Organismo de Formalización de la Propiedad Informal - COFOPRI :: Perú"
		"wms_credit" "COFOPRI"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "-81.30675509 -17.20814673 -69.085388666 -3.49657417600002"
		"wms_srs" "EPSG:4326"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
		"wms_enable_request" "*"
	END
	CLASS
		NAME "Lotes"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 0 0 255
			WIDTH 1
		END
	END
END # Layer